using UnityEngine;

public class RaycastExample : MonoBehaviour
{
    public float rayLength = 10f;
    public LayerMask layerMask;
    public Color rayColor = Color.green;

    private RaycastHit2D hit;

    void Update()
    {
        // 1. Basic raycast from mouse position
        if (Input.GetMouseButtonDown(0))
        {
            // Get mouse position in world coordinates
            Vector3 mousePos = Camera.main.ScreenToWorldPoint(Input.mousePosition);
            Vector3 origin = new Vector3(mousePos.x, mousePos.y, 0);

            // Cast a ray
            RaycastHit2D hit = Physics2D.Raycast(origin, Vector2.zero, 0f, layerMask);

            if (hit.collider != null)
            {
                Debug.Log("Clicked on: " + hit.collider.gameObject.name);

                // Check if it's an enemy
                if (hit.collider.CompareTag("Enemy"))
                {
                    Debug.Log("Hit an enemy!");
                }

                // Check if it's an item
                if (hit.collider.CompareTag("Item"))
                {
                    Debug.Log("Hit an item!");
                }
            }
        }

        // 2. Raycast from a point in a direction
        Vector2 origin2 = transform.position;
        Vector2 direction2 = Vector2.right;

        hit = Physics2D.Raycast(origin2, direction2, rayLength, layerMask);

        if (hit.collider != null)
        {
            Debug.Log("Ray hit: " + hit.collider.gameObject.name);
            Debug.Log("Distance: " + hit.distance);
            Debug.Log("Point: " + hit.point);
            rayColor = Color.red;
        }
        else
        {
            rayColor = Color.green;
        }

        // 3. Raycast in direction of mouse
        if (Input.GetKey(KeyCode.Space))
        {
            Vector3 mousePos = Camera.main.ScreenToWorldPoint(Input.mousePosition);
            Vector2 direction = (mousePos - transform.position).normalized;

            hit = Physics2D.Raycast(transform.position, direction, rayLength, layerMask);

            if (hit.collider != null)
            {
                Debug.Log("Ray hit: " + hit.collider.gameObject.name);
            }
        }
    }

    void OnDrawGizmos()
    {
        // Visualize the ray in the Scene view
        Gizmos.color = rayColor;

        Vector2 direction = Vector2.right;
        Gizmos.DrawRay(transform.position, direction * rayLength);

        // Draw the hit point
        if (hit.collider != null)
        {
            Gizmos.color = Color.red;
            Gizmos.DrawWireSphere(hit.point, 0.2f);
        }
    }

    // Example: Check if there's a wall in front
    public bool IsWallInFront(float distance, LayerMask mask)
    {
        RaycastHit2D hit = Physics2D.Raycast(transform.position, Vector2.right, distance, mask);
        return hit.collider != null;
    }

    // Example: Get object in front
    public GameObject GetObjectInFront(float distance, LayerMask mask)
    {
        RaycastHit2D hit = Physics2D.Raycast(transform.position, Vector2.right, distance, mask);
        if (hit.collider != null)
        {
            return hit.collider.gameObject;
        }
        return null;
    }

    // Example: Line of sight check
    public bool HasLineOfSight(Transform target, LayerMask mask)
    {
        Vector2 direction = (target.position - transform.position).normalized;
        float distance = Vector2.Distance(transform.position, target.position);

        RaycastHit2D hit = Physics2D.Raycast(transform.position, direction, distance, mask);

        // If we hit the target, we have line of sight
        return hit.collider != null && hit.collider.transform == target;
    }
}

